class Solution:
    def kInversePairs(self, n: int, k: int) -> int:
        MOD=10**9+7
        dp=[1]+[0]*k
        for i in range(2,n+1):
            nd=[0]*(k+1); s=0
            for j in range(k+1):
                s=(s+dp[j])%(MOD)
                if j>=i: s=(s-dp[j-i])%MOD
                nd[j]=s
            dp=nd
        return dp[k]

