class Solution {
public:
    int kInversePairs(int n, int k) {
        const int MOD=1e9+7;
        vector<int> dp(k+1,0); dp[0]=1;
        for(int i=2;i<=n;i++){
            vector<int> nd(k+1); long s=0;
            for(int j=0;j<=k;j++){
                s=(s+dp[j])%MOD;
                if(j>=i) s=(s-dp[j-i]+MOD)%MOD;
                nd[j]=s;
            }
            dp=nd;
        }
        return dp[k];
    }
};

