int kInversePairs(int n, int k) {
    const int MOD=1000000007;
    int* dp=calloc(k+1,sizeof(int)); dp[0]=1;
    for(int i=2;i<=n;i++){
        int* nd=calloc(k+1,sizeof(int)); long s=0;
        for(int j=0;j<=k;j++){
            s=(s+dp[j])%MOD; if(j>=i) s=(s-dp[j-i]+MOD)%MOD;
            nd[j]=(int)s;
        }
        free(dp); dp=nd;
    }
    int ans=dp[k]; free(dp); return ans;
}
